export const bodyHtml = "<header>\n        <div class=\"container nav-flex\">\n            <a href=\"/\" class=\"logo\">Noor<span>Link</span></a>\n            </div>\n    </header>\n\n    <!-- VIEW 1: LOGIN (Starts Visible) -->\n    <div id=\"login-view\">\n        <div class=\"login-card\">\n            <div style=\"font-size: 3rem; margin-bottom: 20px;\">🔒</div>\n            <h1>Manage eSIM</h1>\n            <p>Enter your email and order ID to view your data usage and manage your plan.</p>\n            \n            <div class=\"input-group\">\n                <label>Email Address</label>\n                <input type=\"email\" class=\"input-field\" placeholder=\"you@example.com\" value=\"user@demo.com\">\n            </div>\n            \n            <div class=\"input-group\">\n                <label>Order ID</label>\n                <input type=\"text\" class=\"input-field\" placeholder=\"NL-123456\" value=\"NL-882910\">\n            </div>\n\n            <button class=\"login-btn\" onclick=\"showDashboard()\">Find My eSIM</button>\n        </div>\n    </div>\n\n    <!-- VIEW 2: DASHBOARD (Starts Hidden) -->\n    <div class=\"container\" id=\"dashboard-view\">\n        <h2 style=\"margin-bottom: 30px; color: var(--primary);\">Your Active Plan</h2>\n        \n        <div class=\"dash-grid\">\n            \n            <!-- LEFT: DATA VISUAL -->\n            <div class=\"esim-visual-card\">\n                <div style=\"display: flex; justify-content: space-between;\">\n                    <div class=\"status-badge\"><span class=\"pulse-dot\"></span> Active</div>\n                    <div style=\"opacity: 0.8;\">Exp: Feb 28, 2026</div>\n                </div>\n\n                <div class=\"data-circle\">\n                    <span class=\"big-data\">7.5</span>\n                    <span class=\"total-data\">GB left of 10 GB</span>\n                </div>\n\n                <div class=\"progress-container\">\n                    <div class=\"progress-bar\"></div>\n                </div>\n\n                <div class=\"plan-name\">\n                    <strong>Europe Regional Plan</strong><br>\n                    Order #NL-882910\n                </div>\n            </div>\n\n            <!-- RIGHT: ACTIONS -->\n            <div class=\"actions-card\">\n                \n                <button class=\"action-btn\" onclick=\"toggleQR()\">\n                    <span class=\"btn-flex-wrapper\">\n                        <span class=\"btn-icon\"><i class=\"fas fa-qrcode\"></i></span>\n                        <span class=\"btn-content\">Show Install QR Code</span>\n                    </span>\n                    <span class=\"arrow\">▼</span>\n                </button>\n\n                <!-- Hidden QR Section -->\n                <div id=\"qr-display\" class=\"qr-section\">\n                    <div class=\"qr-img\">\n                        <i class=\"fas fa-qrcode\" style=\"font-size: 3rem;\"></i>\n                    </div>\n                    <!-- FIXED: Used HTML entity for Greater Than symbol -->\n                    <p style=\"font-size: 0.9rem; margin-bottom: 10px;\">Scan this in Settings &gt; Cellular &gt; Add eSIM</p>\n                    <div class=\"manual-details\">\n                        <strong>SM-DP+ Address:</strong><br>rsp.truphone.com<br><br>\n                        <strong>Activation Code:</strong><br>JQ-10291-AMZ-1102\n                    </div>\n                </div>\n\n                <button class=\"action-btn\">\n                    <span class=\"btn-flex-wrapper\">\n                        <span class=\"btn-icon\"><i class=\"fas fa-file-invoice\"></i></span>\n                        <span class=\"btn-content\">Download Receipt</span>\n                    </span>\n                    <span class=\"arrow\">→</span>\n                </button>\n\n                <button class=\"action-btn\">\n                    <span class=\"btn-flex-wrapper\">\n                        <span class=\"btn-icon\"><i class=\"fas fa-headset\"></i></span>\n                        <span class=\"btn-content\">Help with this eSIM</span>\n                    </span>\n                    <span class=\"arrow\">→</span>\n                </button>\n\n                <button class=\"top-up-btn\">Top Up Data (+1GB)</button>\n            </div>\n\n        </div>\n    </div>";
export const scripts = ["// CONFIGURATION - Your real backend API\n    const API_BASE_URL = 'https://api.noorlink.co/api';\n    \n    // Keep mock data as fallback\n    const mockDatabase = {\n        \"NL-100\": {\n            status: \"Active\",\n            planName: \"Europe Regional Plan\",\n            dataTotal: 10,\n            dataLeft: 7.5,\n            expiry: \"Feb 28, 2026\",\n            color: \"#10B981\"\n        },\n        \"NL-200\": {\n            status: \"Low Data\",\n            planName: \"USA Travel Pack\",\n            dataTotal: 5,\n            dataLeft: 0.5,\n            expiry: \"Jan 20, 2026\",\n            color: \"#F59E0B\"\n        },\n        \"NL-300\": {\n            status: \"Expired\",\n            planName: \"Turkey Holiday\",\n            dataTotal: 3,\n            dataLeft: 0,\n            expiry: \"Dec 10, 2025\",\n            color: \"#EF4444\"\n        }\n    };\n\n    async function showDashboard() {\n        // 1. Get values from inputs\n        const emailInput = document.querySelector('input[type=\"email\"]').value;\n        const orderInput = document.querySelector('input[type=\"text\"]').value;\n        const errorMsg = document.createElement('p'); // Prepare error message\n\n        // 2. Clear previous errors\n        const existingError = document.querySelector('.error-msg');\n        if(existingError) existingError.remove();\n\n        // 3. Show loading\n        const loginBtn = document.querySelector('.login-btn');\n        const originalText = loginBtn.textContent;\n        loginBtn.textContent = 'Connecting...';\n        loginBtn.disabled = true;\n\n        let data = null;\n\n        // 4. FIRST: Try to get data from your REAL backend\n        try {\n            console.log(`Calling real API: ${API_BASE_URL}/orders/lookup`);\n            \n            const response = await fetch(`${API_BASE_URL}/orders/lookup`, {\n                method: 'POST',\n                headers: {\n                    'Content-Type': 'application/json',\n                },\n                body: JSON.stringify({\n                    email: emailInput,\n                    order_id: orderInput\n                })\n            });\n\n            if (response.ok) {\n                const backendData = await response.json();\n                console.log('✅ Got data from backend:', backendData);\n                \n                // Transform backend data to match your frontend format\n                data = {\n                    status: backendData.status || \"Active\",\n                    planName: backendData.plan_name || \"Europe Regional Plan\",\n                    dataTotal: backendData.data_total || 10,\n                    dataLeft: backendData.data_left || 7.5,\n                    expiry: backendData.expiry_date || \"Feb 28, 2026\",\n                    color: getStatusColor(backendData.status || \"Active\")\n                };\n            } else {\n                console.log('⚠️ Backend error, using mock data');\n                data = mockDatabase[orderInput];\n            }\n        } catch (error) {\n            console.log('❌ Backend call failed, using mock data:', error.message);\n            data = mockDatabase[orderInput];\n        }\n\n        // 5. Process the data (either from backend or mock)\n        if (data) {\n            // --- SUCCESS: UPDATE DASHBOARD UI ---\n            \n            // Update Text\n            document.querySelector('.plan-name strong').textContent = data.planName;\n            document.querySelector('.plan-name').innerHTML = `<strong>${data.planName}</strong><br>Order #${orderInput}`;\n            document.querySelector('.big-data').textContent = data.dataLeft;\n            document.querySelector('.total-data').textContent = `GB left of ${data.dataTotal} GB`;\n            \n            // Update Status Badge\n            const badge = document.querySelector('.status-badge');\n            badge.innerHTML = `<div class=\"pulse-dot\" style=\"background:${data.color}\"></div> ${data.status}`;\n            badge.style.color = data.color;\n            badge.style.borderColor = data.color;\n            badge.style.background = `rgba(0,0,0,0.1)`;\n\n            // Update Progress Bar\n            const percentage = (data.dataLeft / data.dataTotal) * 100;\n            document.querySelector('.progress-bar').style.width = percentage + \"%\";\n            document.querySelector('.progress-bar').style.backgroundColor = data.color;\n\n            // Update Expiry Date\n            document.querySelector('.esim-visual-card div:nth-child(1) div:nth-child(2)').textContent = \n                `Exp: ${data.expiry}`;\n\n            // Store order ID for later API calls\n            window.currentOrderId = orderInput;\n            window.currentUserEmail = emailInput;\n\n            // Show Dashboard\n            document.getElementById('login-view').style.display = 'none';\n            document.getElementById('dashboard-view').style.display = 'block';\n\n        } else {\n            // --- ERROR: SHOW MESSAGE ---\n            errorMsg.className = 'error-msg';\n            errorMsg.style.color = 'red';\n            errorMsg.style.marginTop = '10px';\n            errorMsg.textContent = \"❌ Order ID not found. Try NL-100, NL-200, or NL-300.\";\n            document.querySelector('.login-card').appendChild(errorMsg);\n        }\n\n        // 6. Reset button\n        loginBtn.textContent = originalText;\n        loginBtn.disabled = false;\n    }\n\n    // ENHANCED: Get real QR code from backend\n    async function toggleQR() {\n        const qrBox = document.getElementById('qr-display');\n        \n        if (qrBox.style.display === 'block') {\n            qrBox.style.display = 'none';\n            return;\n        }\n\n        // Show loading\n        qrBox.innerHTML = '<div style=\"padding: 20px; text-align: center;\">Loading QR code...</div>';\n        qrBox.style.display = 'block';\n\n        // Try to get real QR code from backend\n        try {\n            const response = await fetch(`${API_BASE_URL}/esim/qr/${window.currentOrderId}`, {\n                headers: {\n                    'Content-Type': 'application/json',\n                }\n            });\n\n            if (response.ok) {\n                const qrData = await response.json();\n                \n                // Display real QR code\n                qrBox.innerHTML = `\n                    <div class=\"qr-img\">\n                        <img src=\"${qrData.qr_code_url || `https://api.qrserver.com/v1/create-qr-code/?size=150x150&data=esim:${qrData.activation_code || 'DEMO'}`}\" \n                             alt=\"eSIM QR Code\" style=\"width: 100%; height: 100%; object-fit: contain; border-radius: 10px;\">\n                    </div>\n                    <p style=\"font-size: 0.9rem; margin-bottom: 10px;\">Scan this in Settings &gt; Cellular &gt; Add eSIM</p>\n                    <div class=\"manual-details\">\n                        <strong>SM-DP+ Address:</strong><br>${qrData.smdp_address || 'rsp.truphone.com'}<br><br>\n                        <strong>Activation Code:</strong><br>${qrData.activation_code || 'JQ-10291-AMZ-1102'}\n                    </div>\n                `;\n            } else {\n                // Fallback to mock QR\n                showMockQR();\n            }\n        } catch (error) {\n            console.error('Failed to fetch QR:', error);\n            showMockQR();\n        }\n\n        function showMockQR() {\n            qrBox.innerHTML = `\n                <div class=\"qr-img\">\n                    <i class=\"fas fa-qrcode\" style=\"font-size: 3rem;\"></i>\n                </div>\n                <p style=\"font-size: 0.9rem; margin-bottom: 10px;\">Scan this in Settings &gt; Cellular &gt; Add eSIM</p>\n                <div class=\"manual-details\">\n                    <strong>SM-DP+ Address:</strong><br>rsp.truphone.com<br><br>\n                    <strong>Activation Code:</strong><br>JQ-10291-AMZ-1102\n                </div>\n            `;\n        }\n    }\n\n    // ENHANCED: Download real receipt\n    async function downloadReceipt() {\n        try {\n            const response = await fetch(`${API_BASE_URL}/orders/${window.currentOrderId}/receipt`, {\n                method: 'GET',\n                headers: {\n                    'Content-Type': 'application/json',\n                }\n            });\n\n            if (response.ok) {\n                const receiptData = await response.json();\n                \n                // Create download link\n                const link = document.createElement('a');\n                link.href = receiptData.receipt_url || '#';\n                link.download = `receipt-${window.currentOrderId}.pdf`;\n                link.target = '_blank';\n                document.body.appendChild(link);\n                link.click();\n                document.body.removeChild(link);\n                \n                alert('Receipt download started!');\n            } else {\n                alert('Receipt will be available soon. For now, please contact support.');\n            }\n        } catch (error) {\n            console.error('Receipt download error:', error);\n            alert('Receipt service temporarily unavailable.');\n        }\n    }\n\n    // ENHANCED: Real top-up functionality\n    async function topUpData() {\n        const amount = prompt('How many GB would you like to add?', '1');\n        if (!amount || isNaN(amount)) return;\n\n        try {\n            const response = await fetch(`${API_BASE_URL}/orders/${window.currentOrderId}/topup`, {\n                method: 'POST',\n                headers: {\n                    'Content-Type': 'application/json',\n                },\n                body: JSON.stringify({\n                    additional_gb: parseFloat(amount),\n                    email: window.currentUserEmail\n                })\n            });\n\n            if (response.ok) {\n                const result = await response.json();\n                alert(`✅ ${result.message || `Successfully added ${amount}GB!`}`);\n                \n                // Refresh the dashboard to show new data\n                showDashboard();\n            } else {\n                const error = await response.json();\n                alert(`Failed: ${error.detail || 'Top-up service unavailable'}`);\n            }\n        } catch (error) {\n            console.error('Top-up error:', error);\n            alert('Top-up service temporarily unavailable. Please try again later.');\n        }\n    }\n\n    // Helper function\n    function getStatusColor(status) {\n        const colors = {\n            'Active': '#10B981',\n            'Low Data': '#F59E0B',\n            'Expired': '#EF4444',\n            'Pending': '#6B7280',\n            'Activated': '#3B82F6',\n            'active': '#10B981',\n            'expired': '#EF4444',\n            'low_data': '#F59E0B'\n        };\n        return colors[status] || '#6B7280';\n    }\n\n    // Test backend connection on page load\n    document.addEventListener('DOMContentLoaded', async function() {\n        console.log('Testing connection to backend:', API_BASE_URL);\n        \n        try {\n            const response = await fetch(`${API_BASE_URL.replace('/api', '')}/health`);\n            const data = await response.json();\n            \n            if (data.status === 'operational') {\n                console.log('✅ Backend is operational');\n                // Add a subtle indicator\n                const subtitle = document.querySelector('.login-card p');\n                subtitle.innerHTML += '<br><small style=\"color: var(--success);\">✓ Connected to NoorLink API</small>';\n            }\n        } catch (error) {\n            console.warn('⚠️ Backend not reachable, using mock mode');\n            const subtitle = document.querySelector('.login-card p');\n            subtitle.innerHTML += '<br><small style=\"color: var(--accent);\">⚠️ Using demo mode</small>';\n        }\n    });\n\n    // Update button event listeners\n    document.addEventListener('DOMContentLoaded', function() {\n        // Update receipt button\n        const receiptBtn = document.querySelectorAll('.action-btn')[1];\n        receiptBtn.onclick = downloadReceipt;\n        \n        // Update help button (optional)\n        const helpBtn = document.querySelectorAll('.action-btn')[2];\n        helpBtn.onclick = function() {\n            window.location.href = 'https://noorlink.co/support';\n        };\n        \n        // Update top-up button\n        const topUpBtn = document.querySelector('.top-up-btn');\n        topUpBtn.onclick = topUpData;\n    });"];
